  // Audio state
  let _bgm = null;
  let _bgmEnabled = true;
  let _sfxEnabled = true;
  let _volume = 0.06; // 0–1, last non-zero volume level (reduced by 70%)

  function playBGM(trackName) {
    if (!_bgmEnabled) return;
    stopBGM();
    const url = MUSIC_BASE + (trackName || BATTLE_TRACKS[Math.floor(Math.random()*BATTLE_TRACKS.length)]);
    _bgm = new Audio(url);
    _bgm.loop = true;
    _bgm.volume = _volume * 0.3;
    _bgm.play().catch(()=>{});
  }

  function stopBGM() {
    if (_bgm) {
      _bgm.pause();
      _bgm.currentTime = 0;
      _bgm = null;
    }
  }

  function playVictoryJingle() {
    stopBGM();
    if (!_bgmEnabled) return;
    // Always play synth fanfare immediately as guaranteed feedback
    _synthVictory();
    // Also try streaming music in background
    const url = MUSIC_BASE + 'bw2-rival.mp3';
    _bgm = new Audio(url);
    _bgm.volume = Math.min(1, _volume * 0.3);
    _bgm.loop = false;
    _bgm.play().catch(()=>{});
  }

  function playDefeatJingle() {
    stopBGM();
    if (!_bgmEnabled) return;
    // Always play synth defeat sounds immediately
    _synthDefeat();
    // Also try streaming music
    const url = MUSIC_BASE + 'bw-loss.mp3';
    _bgm = new Audio(url);
    _bgm.volume = Math.min(1, _volume * 0.3);
    _bgm.play().catch(()=>{});
  }

  function playCry(monName, monId) {
    if (!_sfxEnabled) return;
    const id = monId || _nameToId(monName);
    if (!id) return;
    const url = CRY_BASE + id + '.ogg';
    const a = new Audio(url);
    a.volume = Math.min(1, _volume * 2);
    a.play().catch(()=>{
      // Fallback: synthesize a simple cry-like sound
      _synthTone(300 + (id % 8) * 40, 0.3, 'sine', 0.18, 200 + (id % 5) * 30);
    });
  }

  // Map pokemon names to their IDs for cry lookup
  const _NAME_ID = {};
  function _buildNameIdMap() {
    if (Object.keys(_NAME_ID).length) return;
    // Build from ROSTER_DEDUP after it's available
    if (typeof ROSTER_DEDUP !== 'undefined') {
      ROSTER_DEDUP.forEach(p => { _NAME_ID[p.name.toLowerCase()] = p.id; });
    }
  }
  function _nameToId(name) {
    _buildNameIdMap();
    return _NAME_ID[name.toLowerCase()] || null;
  }

  function playMoveSFX(moveName) {
    if (!_sfxEnabled) return;
    const file = MOVE_SFX[moveName];
    if (!file) {
      // No specific move SFX — play real hit sound from repo as fallback
      const a = new Audio(SE_BASE + 'Battle%20damage%20normal.ogg');
      a.volume = Math.min(1, _volume * 2);
      a.play().catch(()=>{ _synthHit(1); });
      return;
    }
    const url = SFX_BASE + encodeURIComponent(file);
    const a = new Audio(url);
    a.volume = Math.min(1, _volume * 2);
    // If khinsider fails, fall back to real repo damage sound
    a.play().catch(()=>{
      const b = new Audio(SE_BASE + 'Battle%20damage%20normal.ogg');
      b.volume = Math.min(1, _volume * 2);
      b.play().catch(()=>{ _synthHit(1); });
    });
  }

  function playFaintSFX() {
    if (!_sfxEnabled) return;
    // Real faint SFX from Pokemon Essentials repo
    const a = new Audio(SE_BASE + 'Pkmn%20faint.ogg');
    a.volume = Math.min(1, _volume * 1.8);
    a.play().catch(()=>{ if (_sfxEnabled) _synthFaint(); });
  }

  function playHitSFX(effectiveness) {
    if (!_sfxEnabled) return;
    // Real hit SFX from Pokemon Essentials repo
    let file;
    if (effectiveness === 0)     file = null; // no effect — keep synth beep
    else if (effectiveness >= 2) file = 'Battle%20damage%20super.ogg';
    else if (effectiveness < 1)  file = 'Battle%20damage%20weak.ogg';
    else                         file = 'Battle%20damage%20normal.ogg';
    if (!file) { _synthNoEffect(); return; }
    const a = new Audio(SE_BASE + file);
    a.volume = Math.min(1, _volume * 2);
    a.play().catch(()=>{
      if (effectiveness >= 2)     _synthSuperEffective();
      else if (effectiveness < 1) _synthNotVeryEffective();
      else                        _synthHit(1);
    });
  }

  /* ── Web Audio synthesized SFX ───────────────────────────── */
  let _audioCtx = null;
  function _getCtx() {
    if (!_audioCtx) {
      _audioCtx = new (window.AudioContext||window.webkitAudioContext)();
    }
    // Resume if suspended (browser autoplay policy)
    if (_audioCtx.state === 'suspended') {
      _audioCtx.resume().catch(()=>{});
    }
    return _audioCtx;
  }
  // Resume audio context on any user interaction with the battle UI
  function _resumeAudio() {
    if (_audioCtx && _audioCtx.state === 'suspended') _audioCtx.resume().catch(()=>{});
    else if (!_audioCtx) _getCtx(); // pre-create on first gesture
  }
  function _synthTone(freq, duration, type='square', vol=0.15, freqEnd=null) {
    try {
      const ctx = _getCtx();
      if (ctx.state === 'suspended') return; // still suspended, give up
      const osc = ctx.createOscillator();
      const gain = ctx.createGain();
      osc.connect(gain); gain.connect(ctx.destination);
      osc.type = type;
      osc.frequency.setValueAtTime(freq, ctx.currentTime);
      if (freqEnd) osc.frequency.linearRampToValueAtTime(freqEnd, ctx.currentTime + duration);
      gain.gain.setValueAtTime(vol * _volume, ctx.currentTime);
      gain.gain.exponentialRampToValueAtTime(0.001, ctx.currentTime + duration);
      osc.start(ctx.currentTime);
      osc.stop(ctx.currentTime + duration);
    } catch(e) {}
  }
  function _synthHit(eff) {
    _synthTone(220, 0.12, 'sawtooth', 0.18);
    setTimeout(()=>_synthTone(180, 0.1, 'square', 0.12), 40);
  }
  function _synthSuperEffective() {
    _synthTone(440, 0.08, 'square', 0.2);
    setTimeout(()=>_synthTone(550, 0.08, 'square', 0.22), 60);
    setTimeout(()=>_synthTone(660, 0.12, 'square', 0.25), 120);
  }
  function _synthNotVeryEffective() {
    _synthTone(180, 0.15, 'sine', 0.12);
    setTimeout(()=>_synthTone(150, 0.15, 'sine', 0.08), 80);
  }
  function _synthNoEffect() {
    _synthTone(120, 0.2, 'sine', 0.08);
  }
  function _synthFaint() {
    // Descending tone — classic faint sound
    _synthTone(400, 0.4, 'sine', 0.18, 80);
    setTimeout(()=>_synthTone(200, 0.4, 'sine', 0.12, 40), 200);
  }
  function _synthVictory() {
    // Simple ascending fanfare
    const notes = [523, 659, 784, 1047];
    notes.forEach((f, i) => setTimeout(()=>_synthTone(f, 0.18, 'square', 0.2), i * 120));
    setTimeout(()=>_synthTone(1047, 0.5, 'square', 0.25), notes.length * 120);
  }
  function _synthDefeat() {
    // Descending sad tones
    const notes = [392, 330, 294, 220];
    notes.forEach((f, i) => setTimeout(()=>_synthTone(f, 0.22, 'sine', 0.16), i * 180));
  }
  // Real Pokémon Essentials "Mart buy item" sound effect
  // Source: github.com/omanoloneto/pokemon-essentials-enhanced-v20.1 (Audio/SE)
  const ITEM_PICKUP_SFX = SE_BASE + 'Mart%20buy%20item.ogg';
  function playItemPickupSFX() {
    if (!_sfxEnabled) return;
    const a = new Audio(ITEM_PICKUP_SFX);
    a.volume = Math.min(1, _volume * 2);
    a.play().catch(()=>{
      // Fallback synth if CDN fails
      const notes = [1047, 1319, 1568, 2093];
      notes.forEach((f, i) => setTimeout(()=>_synthTone(f, i < 3 ? 0.08 : 0.28, 'sine', 0.22), i * 80));
    });
  }

  /* ── Type effectiveness ─────────────────────────────────── */
  const TYPE_CHART = {
    fire:    {grass:2,ice:2,bug:2,steel:2,  water:0.5,fire:0.5,rock:0.5,dragon:0.5},
    water:   {fire:2,ground:2,rock:2,        water:0.5,grass:0.5,dragon:0.5},
    grass:   {water:2,ground:2,rock:2,        fire:0.5,grass:0.5,poison:0.5,flying:0.5,bug:0.5,dragon:0.5,steel:0.5},
    electric:{water:2,flying:2,               electric:0.5,grass:0.5,dragon:0.5,ground:0},
    ice:     {grass:2,ground:2,flying:2,dragon:2, fire:0.5,water:0.5,ice:0.5,steel:0.5},
    fighting:{normal:2,ice:2,rock:2,dark:2,steel:2, poison:0.5,bug:0.5,psychic:0.5,flying:0.5,fairy:0.5,ghost:0},
    poison:  {grass:2,fairy:2,                poison:0.5,ground:0.5,rock:0.5,ghost:0.5,steel:0},
    ground:  {fire:2,electric:2,poison:2,rock:2,steel:2, grass:0.5,bug:0.5,flying:0},
    flying:  {grass:2,fighting:2,bug:2,       electric:0.5,rock:0.5,steel:0.5},
    psychic: {fighting:2,poison:2,            psychic:0.5,steel:0.5,dark:0,ghost:0},
    bug:     {grass:2,psychic:2,dark:2,       fire:0.5,fighting:0.5,flying:0.5,ghost:0.5,steel:0.5,fairy:0.5},
    rock:    {fire:2,ice:2,flying:2,bug:2,    fighting:0.5,ground:0.5,steel:0.5},
    ghost:   {ghost:2,psychic:2,              normal:0,fighting:0,dark:0.5},
    dragon:  {dragon:2,                       steel:0.5,fairy:0},
    dark:    {ghost:2,psychic:2,              fighting:0.5,dark:0.5,fairy:0.5},
    steel:   {ice:2,rock:2,fairy:2,           fire:0.5,water:0.5,electric:0.5,steel:0.5,poison:0},
    normal:  {                                rock:0.5,steel:0.5,ghost:0},
    fairy:   {fighting:2,dragon:2,dark:2,     fire:0.5,poison:0.5,steel:0.5},
  };
  function typeEff(moveType, defTypes) {
    let m = 1;
    for (const dt of defTypes) { const r=TYPE_CHART[moveType]||{}; m*=(r[dt]!==undefined?r[dt]:1); }
    return m;
  }

  /* ════════════════════════════════════════════════════════
     STATUS EFFECTS ENGINE
     ════════════════════════════════════════════════════════ */

  // Status immunity rules
  const STATUS_IMMUNE = {
    brn: ['fire'],            // Fire types can't be burned
    psn: ['poison','steel'],  // Poison/Steel types can't be poisoned
    tox: ['poison','steel'],
    par: ['electric'],        // Electric types can't be paralysed
    frz: ['ice'],             // Ice types can't be frozen
  };

  function canInflictStatus(mon, statusKey) {
    if (mon.status) return false; // already has a status
    const immune = STATUS_IMMUNE[statusKey] || [];
    return !mon.types.some(t => immune.includes(t));
  }

  function inflictStatus(mon, statusKey) {
    if (!canInflictStatus(mon, statusKey)) return false;
    mon.status = statusKey;
    mon.statusTurns = statusKey === 'slp' ? (2 + Math.floor(Math.random()*4)) : 0;
    return true;
  }

  function cureStatus(mon) {
    mon.status = null;
    mon.statusTurns = 0;
  }

  // Synth sounds for status conditions
  function _synthStatusSFX(status) {
    if (status==='brn') { _synthTone(800,0.12,'sawtooth',0.18,400); setTimeout(()=>_synthTone(600,0.18,'sawtooth',0.14,200),80); }
    else if (status==='psn'||status==='tox') { _synthTone(150,0.35,'sine',0.14,100); setTimeout(()=>_synthTone(200,0.2,'square',0.1,180),120); }
    else if (status==='par') { _synthTone(660,0.06,'square',0.2); setTimeout(()=>_synthTone(440,0.06,'square',0.2),40); setTimeout(()=>_synthTone(330,0.12,'square',0.15),80); }
    else if (status==='slp') { _synthTone(220,0.5,'sine',0.12,180); setTimeout(()=>_synthTone(180,0.6,'sine',0.1,160),300); }
    else if (status==='frz') { _synthTone(1200,0.12,'sawtooth',0.15,2000); setTimeout(()=>_synthTone(900,0.3,'sawtooth',0.12,400),100); }
  }

  // Returns true if attacker is blocked by status this turn (skip-turn effects)
  // Also handles status damage at end of turn
  function checkStatusBeforeMove(mon, whoStr, onBlocked, onFree) {
    if (!mon.status) { onFree(); return; }

    if (mon.status === 'slp') {
      if (mon.statusTurns > 0) {
        mon.statusTurns--;
        log(`${mon.name} is fast asleep...`, onBlocked);
      } else {
        cureStatus(mon);
        log(`${mon.name} woke up!`, ()=>{ renderHP(whoStr); onFree(); });
      }
      return;
    }

    if (mon.status === 'frz') {
      if (Math.random() < 0.2) {
        // Thaw
        cureStatus(mon);
        log(`${mon.name} thawed out!`, ()=>{ renderHP(whoStr); onFree(); });
      } else {
        log(`${mon.name} is frozen solid!`, onBlocked);
      }
      return;
    }

    if (mon.status === 'par') {
      if (Math.random() < 0.25) {
        log(`${mon.name} is fully paralyzed! It can't move!`, onBlocked);
        return;
      }
    }

    // Check attract (infatuation) — 50% chance to be immobilized
    if (mon.infatuated) {
      checkAttractBeforeMove(mon, whoStr, onBlocked, ()=>{
        // Check confusion after attract
        checkConfusionBeforeMove(mon, whoStr, onBlocked, onFree);
      });
      return;
    }

    // Check confusion
    checkConfusionBeforeMove(mon, whoStr, onBlocked, onFree);
  }

  // Apply end-of-turn status damage (burn, poison, tox)
  function applyEndOfTurnStatus(mon, whoStr, onDone) {
    const afterMainStatus = () => {
      // Binding damage runs after main status damage
      if (mon.bound && mon.hp > 0) {
        applyBindingDamage(mon, whoStr, onDone);
      } else {
        onDone();
      }
    };

    if (!mon.status || mon.hp <= 0) { afterMainStatus(); return; }

    if (mon.status === 'brn') {
      const dmg = Math.max(1, Math.floor(mon.maxHP / 16));
      mon.hp = Math.max(0, mon.hp - dmg);
      _synthStatusSFX('brn');
      showDmgFloat(whoStr, dmg, 'burn');
      renderHP(whoStr); renderParty();
      log(`${mon.name} is hurt by its burn!`, ()=>{
        if (mon.hp <= 0) doFaint(whoStr, onDone);
        else afterMainStatus();
      });
      return;
    }

    if (mon.status === 'psn') {
      const dmg = Math.max(1, Math.floor(mon.maxHP / 8));
      mon.hp = Math.max(0, mon.hp - dmg);
      _synthStatusSFX('psn');
      showDmgFloat(whoStr, dmg, 'status');
      renderHP(whoStr); renderParty();
      log(`${mon.name} is hurt by poison!`, ()=>{
        if (mon.hp <= 0) doFaint(whoStr, onDone);
        else afterMainStatus();
      });
      return;
    }

    if (mon.status === 'tox') {
      mon.statusTurns = (mon.statusTurns || 0) + 1;
      const dmg = Math.max(1, Math.floor(mon.maxHP * mon.statusTurns / 16));
      mon.hp = Math.max(0, mon.hp - dmg);
      _synthStatusSFX('tox');
      showDmgFloat(whoStr, dmg, 'status');
      renderHP(whoStr); renderParty();
      log(`${mon.name} is badly poisoned! (${mon.statusTurns}x)`, ()=>{
        if (mon.hp <= 0) doFaint(whoStr, onDone);
        else afterMainStatus();
      });
      return;
    }

    afterMainStatus();
  }

