  const _origShowDmgFloat = showDmgFloat;
  // Will override after definition

  /* ════════════════════════════════════════════════════════
     STAT STAGE ENGINE
     ════════════════════════════════════════════════════════ */

  // Each pokemon carries a `stages` object: {atk:0, def:0, spa:0, spd:0, spe:0, acc:0, eva:0}
  // Stages range from -6 to +6.  Multipliers per stage (Gen 5+ standard):
  const STAGE_MULT = [2/8, 2/7, 2/6, 2/5, 2/4, 2/3, 1, 3/2, 4/2, 5/2, 6/2, 7/2, 8/2];
  // Index 6 = stage 0 (mult 1.0). stageIndex(s) = s + 6.
  function stageMult(s) { return STAGE_MULT[Math.max(0, Math.min(12, s + 6))]; }

  function initStages(mon) {
    if (!mon.stages) mon.stages = {atk:0,def:0,spa:0,spd:0,spe:0,acc:0,eva:0};
  }
  function resetStages(mon) {
    mon.stages = {atk:0,def:0,spa:0,spd:0,spe:0,acc:0,eva:0};
    // Clear all volatile conditions on switch-out/faint
    mon.confused    = false;
    mon.confuseTurns= 0;
    mon.infatuated  = false;
    mon.bound       = null;
    mon.protectActive = false;
    mon.protectCount  = 0;
  }

  // Returns the effective stat value after applying stages
  function effectiveStat(mon, stat) {
    initStages(mon);
    const base = mon[stat] !== undefined ? mon[stat] : 0;
    return Math.floor(base * stageMult(mon.stages[stat] || 0));
  }

  // Apply a stage change. Returns actual amount changed (clamped).
  function applyStage(mon, stat, delta) {
    initStages(mon);
    const prev = mon.stages[stat] || 0;
    const next = Math.max(-6, Math.min(6, prev + delta));
    mon.stages[stat] = next;
    return next - prev; // actual change
  }

  // Render stat stage badges on the HP bar
  function renderStages(who) {
    const mon = (who==='me'?myTeam:oppTeam)[(who==='me'?myActive:oppActive)];
    const el  = document.getElementById(`pkm-${who}-stages`);
    if (!el || !mon) return;
    initStages(mon);
    const LABELS = {atk:'ATK',def:'DEF',spa:'SpA',spd:'SpD',spe:'SPE',acc:'ACC',eva:'EVA'};
    let html = '';
    for (const [stat, val] of Object.entries(mon.stages)) {
      if (val === 0) continue;
      const sign  = val > 0 ? '+' : '';
      const cls   = val > 0 ? 'up' : 'down';
      html += `<span class="pkm-stage-badge ${cls}">${LABELS[stat]}${sign}${val}</span>`;
    }
    el.innerHTML = html;
  }

  // Show a floating stat change message over the sprite
  function showStatFloat(who, text, dir) {
    const field = document.getElementById('pkm-field');
    if (!field) return;
    const el  = document.createElement('div');
    el.className = `pkm-stat-float ${dir}`;
    el.textContent = text;
    const base = who==='opp' ? {left:'65%', top:'42%'} : {left:'8%', top:'58%'};
    el.style.left = base.left; el.style.top = base.top;
    field.appendChild(el);
    setTimeout(() => el.remove(), 1500);
  }

  // Synth sound for stat boost/drop
  function _synthStatChange(up) {
    if (up) {
      _synthTone(440, 0.08, 'sine', 0.16);
      setTimeout(()=>_synthTone(550, 0.08, 'sine', 0.18), 70);
      setTimeout(()=>_synthTone(660, 0.12, 'sine', 0.2),  140);
    } else {
      _synthTone(330, 0.1, 'sine', 0.16);
      setTimeout(()=>_synthTone(220, 0.12, 'sine', 0.14), 80);
    }
  }

