  // Describes stat name for log messages
  const STAT_LABEL = { atk:'Attack', def:'Defense', spa:'Sp. Atk', spd:'Sp. Def', spe:'Speed', acc:'accuracy', eva:'evasion' };

  // Execute a stat-change move (power:0, pure stat change). Returns false if nothing happened.
  function execStatMove(attacker, mv, onDone) {
    const atkTeam = attacker==='me' ? myTeam : oppTeam;
    const defTeam = attacker==='me' ? oppTeam : myTeam;
    const atkIdx  = attacker==='me' ? myActive : oppActive;
    const defIdx  = attacker==='me' ? oppActive : myActive;
    const atk     = atkTeam[atkIdx];
    const def     = defTeam[defIdx];
    const who_atk = attacker;
    const who_def = attacker==='me' ? 'opp' : 'me';

    const sme = STAT_MOVE_EFFECTS[mv.name];
    if (!sme || sme.changes.length === 0) {
      log('But it failed!', onDone);
      return true;
    }

    const target = sme.target === 'self' ? atk : def;
    const who    = sme.target === 'self' ? who_atk : who_def;

    initStages(target);
    let anyChanged = false;
    let msgs = [];
    for (const {stat, delta} of sme.changes) {
      const actual = applyStage(target, stat, delta);
      if (actual !== 0) {
        anyChanged = true;
        const dir    = actual > 0 ? 'up' : 'down';
        const amt    = Math.abs(actual);
        const adv    = amt >= 3 ? 'greatly' : amt >= 2 ? 'sharply' : '';
        const verb   = actual > 0 ? 'rose' : 'fell';
        msgs.push({ text: `${target.name}'s ${STAT_LABEL[stat]} ${adv ? adv+' ' : ''}${verb}!`, dir, who, stat: actual });
      } else {
        msgs.push({ text: `${target.name}'s ${STAT_LABEL[delta>0?'atk':delta<0?'atk':'atk']} won't go ${delta>0?'higher':'lower'}!`, dir:null, who, stat:0 });
      }
    }
    if (!anyChanged) { log(`It won't go ${sme.changes[0].delta>0?'higher':'lower'}!`, onDone); return true; }

    _synthStatChange(sme.target==='self' ? sme.changes[0].delta > 0 : sme.changes[0].delta < 0);
    // Show float for first changed stat
    const firstUp  = sme.changes.find(c=>c.delta>0);
    const firstDwn = sme.changes.find(c=>c.delta<0);
    if (firstUp)  showStatFloat(sme.target==='self'?who_atk:who_def, '▲ '+STAT_LABEL[firstUp.stat].toUpperCase(),  'up');
    if (firstDwn) showStatFloat(sme.target==='self'?who_atk:who_def, '▼ '+STAT_LABEL[firstDwn.stat].toUpperCase(), 'down');
    renderStages(who_atk); renderStages(who_def);

    // Log all messages in sequence
    const logAll = (i) => {
      if (i >= msgs.length) { onDone(); return; }
      log(msgs[i].text, () => logAll(i+1));
    };
    logAll(0);
    return true;
  }

  // Apply secondary stat effect after a damaging move lands (chance-based)
  function applySecondaryStatEffect(attacker, mv, onDone) {
    const sme = STAT_MOVE_EFFECTS[mv.name];
    if (!sme || sme.changes.length === 0 || sme.chance === undefined) { onDone(); return; }
    // Only proc if random roll passes
    if (Math.random() >= sme.chance) { onDone(); return; }

    const atkTeam = attacker==='me' ? myTeam : oppTeam;
    const defTeam = attacker==='me' ? oppTeam : myTeam;
    const atk     = atkTeam[attacker==='me'?myActive:oppActive];
    const def     = defTeam[attacker==='me'?oppActive:myActive];
    const who_atk = attacker;
    const who_def = attacker==='me' ? 'opp' : 'me';

    const target = sme.target === 'self' ? atk : def;
    const who    = sme.target === 'self' ? who_atk : who_def;

    initStages(target);
    let msgs = [];
    let anyChanged = false;
    for (const {stat, delta} of sme.changes) {
      const actual = applyStage(target, stat, delta);
      if (actual !== 0) {
        anyChanged = true;
        const amt  = Math.abs(actual);
        const adv  = amt >= 3 ? 'greatly' : amt >= 2 ? 'sharply' : '';
        const verb = actual > 0 ? 'rose' : 'fell';
        msgs.push(`${target.name}'s ${STAT_LABEL[stat]} ${adv ? adv+' ' : ''}${verb}!`);
      }
    }
    if (!anyChanged) { onDone(); return; }

    const firstUp  = sme.changes.find(c=>c.delta>0);
    const firstDwn = sme.changes.find(c=>c.delta<0);
    if (firstUp)  showStatFloat(sme.target==='self'?who_atk:who_def, '▲ '+STAT_LABEL[firstUp.stat].toUpperCase(),  'up');
    if (firstDwn) showStatFloat(sme.target==='self'?who_atk:who_def, '▼ '+STAT_LABEL[firstDwn.stat].toUpperCase(), 'down');
    _synthStatChange(sme.target==='self' ? (sme.changes[0].delta > 0) : (sme.changes[0].delta < 0));
    renderStages(who_atk); renderStages(who_def);

    const logAll = (i) => {
      if (i >= msgs.length) { onDone(); return; }
      log(msgs[i], () => logAll(i+1));
    };
    logAll(0);
  }


