  /* ════════════════════════════════════════════════════════
     PROTECT / DETECT
     Each Pokémon gets a `protectActive` flag that blocks
     all damaging + status moves for one turn. Successive
     uses have a 50% failure chance (standard Gen 6+).
     ════════════════════════════════════════════════════════ */

  // Show a pulsing blue shield over the protected side, keep it until clearProtect()
  function showProtectShield(who) {
    clearProtectShield(who); // remove any leftover
    const field = document.getElementById('pkm-field');
    if (!field) return;
    const el = document.createElement('div');
    el.id = `pkm-shield-${who}`;
    el.className = `pkm-protect-shield ${who}`;
    field.appendChild(el);
  }

  function clearProtectShield(who) {
    const el = document.getElementById(`pkm-shield-${who}`);
    if (!el) return;
    el.classList.add('fade-out');
    setTimeout(()=>el.remove(), 420);
  }

  // Synth a short protective-barrier sound
  function _synthProtectSFX() {
    _synthTone(523, 0.05, 'sine', 0.12);
    setTimeout(()=>_synthTone(659, 0.05, 'sine', 0.12), 60);
    setTimeout(()=>_synthTone(784, 0.08, 'sine', 0.18), 120);
    setTimeout(()=>_synthTone(1047,0.06, 'sine', 0.14), 200);
  }

  // Execute Protect/Detect/King's Shield. Returns true if handled.
  function execProtect(attacker, mv, onDone) {
    if (mv.name !== 'Protect' && mv.name !== 'Detect' && mv.name !== "King's Shield") return false;

    const atkTeam = attacker==='me' ? myTeam : oppTeam;
    const mon     = atkTeam[attacker==='me' ? myActive : oppActive];
    const who     = attacker;

    // Consecutive protect: 50% chance to fail each extra use
    if (mon.protectCount > 0 && Math.random() < 0.5) {
      log(`But it failed!`, onDone);
      mon.protectCount = 0; // reset streak on failure
      return true;
    }

    // Activate protect
    mon.protectActive = true;
    mon.protectCount  = (mon.protectCount || 0) + 1;

    playMoveSFX(mv.name);
    playAttackAnim(mv.type, attacker, ()=>{
      _synthProtectSFX();
      showProtectShield(who);
      log(`${mon.name} protected itself!`, onDone);
    });
    return true;
  }

  // Clear protect at end of turn for a given side
  function clearProtect(who) {
    const team = who==='me' ? myTeam : oppTeam;
    const mon  = team[who==='me' ? myActive : oppActive];
    if (!mon) return;
    if (mon.protectActive) {
      clearProtectShield(who);
      mon.protectActive = false;
    }
    // Reset consecutive counter if they didn't use Protect this turn
    // (tracked in execSoloTurn / online turn resolution)
  }

  /* ════════════════════════════════════════════════════════
     MULTI-HIT MOVES
     ════════════════════════════════════════════════════════ */
  // Fixed hit count (always hits exactly N times)
  const FIXED_MULTIHIT = {
    'Dual Chop':       2,
    'Double Hit':      2,
    'Double Kick':     2,
    'Bonemerang':      2,
    'Gear Grind':      2,
    'Dragon Darts':    2,
    'Twineedle':       2,
    'Double Slap':     2,
  };

  // Variable hit count: rolls 2–5 with weighted distribution (2=35%, 3=35%, 4=15%, 5=15%)
  const VARIABLE_MULTIHIT = new Set([
    'Bullet Seed','Rock Blast','Icicle Spear','Tail Slap',
    'Arm Thrust','Pin Missile','Fury Attack','Fury Swipes',
    'Comet Punch','Barrage','Spike Cannon','Water Shuriken', // Water Shuriken: 3 hits average
  ]);

  // Water Shuriken hits 3 times consistently (unique)
  const TRIPLE_HIT = new Set(['Triple Kick','Triple Axel']);

  function rollMultiHitCount(mvName) {
    if (FIXED_MULTIHIT[mvName]) return FIXED_MULTIHIT[mvName];
    if (TRIPLE_HIT.has(mvName)) return 3;
    if (mvName === 'Water Shuriken') return 3;
    if (VARIABLE_MULTIHIT.has(mvName)) {
      const r = Math.random();
      return r < 0.35 ? 2 : r < 0.70 ? 3 : r < 0.85 ? 4 : 5;
    }
    return 1; // not a multi-hit move
  }

  /* ════════════════════════════════════════════════════════
     CONFUSION  (volatile — clears on switch)
     25% chance to hit self each turn (50 base power, physical)
     Lasts 2–5 turns, then snaps out automatically.
     ════════════════════════════════════════════════════════ */
  const CONFUSION_MOVES = new Set([
    'Confuse Ray','Sweet Kiss','Supersonic','Flatter','Swagger',
    'Teeter Dance','Hurricane','Dynamic Punch','Signal Beam',
    'Dizzy Punch','Psybeam',
  ]);
