  const _idToBaseId = {};
  for (const [baseId, chain] of Object.entries(EVOLUTION_CHAINS)) {
    for (const stage of chain) _idToBaseId[stage.id] = Number(baseId);
  }

  // Given baseId + level, return the correct stage's id & name
  function _resolveEvolutionStage(baseId, level) {
    const chain = EVOLUTION_CHAINS[baseId];
    if (!chain) return null;
    let stage = chain[0];
    for (const s of chain) {
      if (level >= s.minLevel) stage = s;
    }
    return stage;
  }

