  // Merge base forms into ROSTER_DEDUP (base forms first so they don't override evolved)
  for (const bf of BASE_FORMS) {
    if (!seen.has(bf.id)) { seen.add(bf.id); ROSTER_DEDUP.push(bf); }
  }

  /* ── Chain-aware progress helpers ────────────────────────── */
  // Progress is always stored under the BASE id of the chain
  function _getChainBaseId(id) {
    return _idToBaseId[id] !== undefined ? _idToBaseId[id] : id;
  }
  // Get the template for a mon at a given chain level (resolves evolution)
  function _getTemplateForChain(baseId, level) {
    const stage = _resolveEvolutionStage(baseId, level);
    if (!stage) return ROSTER_DEDUP.find(r=>r.id===baseId);
    return ROSTER_DEDUP.find(r=>r.id===stage.id);
  }

  // STARTERS: now the BASE form IDs (not evolved)
  const STARTERS = [4,7,1,172,92,129,147,143,131,58,133,197,280,390,393,487,636,700,656,887]
    .map(id=>ROSTER_DEDUP.find(p=>p.id===id)).filter(Boolean);

  /* ══════════════════════════════════════════════════════════
     LEVEL / XP SYSTEM
     ══════════════════════════════════════════════════════════ */

  /* Learnset: every Pokémon learns moves at these level thresholds.
     Moves in the ROSTER are ordered weakest→strongest.
     We map them to level gates so early levels get fewer/weaker moves. */
  const LEARNSET_GATES = [1, 10, 25, 45]; // level to unlock move slot 0,1,2,3

  /* XP table: how much XP needed to reach each level (cumulative).
     Medium-fast curve: xp = (level^3). We store xp needed FOR level. */
  function xpForLevel(lv) { return Math.floor(Math.pow(lv,3)); }
  function xpToNext(lv)   { return xpForLevel(lv+1) - xpForLevel(lv); }

  /* XP gained per enemy fainted (scales with enemy level) */
  function xpYield(enemyLv) { return Math.floor(50 + enemyLv * 5); }

  /* ── Persistent storage (per device/browser) ────────────── */
  // localStorage is scoped to this device + browser, so each machine
  // automatically has its own independent Pokémon progress.
  /* ══════════════════════════════════════════════════════════
     PERSISTENT SAVE SYSTEM
     Single master key that never changes, with migration from
     any previous key format so no progress is ever lost.
     ══════════════════════════════════════════════════════════ */

  const SAVE_KEY = 'pkm_save'; // THIS KEY MUST NEVER CHANGE

  /* ── Default save shape ────────────────────────────────── */
  function _defaultSave() {
    return { levels: {}, coins: 0, inventory: {}, presets: [null,null,null,null,null], shinies: [] };
  }

  /* ── Migration: read any old key format ────────────────── */
  function _migrate(save) {
    // Pull in progress from old versioned keys if present and save is empty
    const tryOld = (key, dflt) => {
      try {
        const v = localStorage.getItem(key);
        return v ? JSON.parse(v) : dflt;
      } catch(e) { return dflt; }
    };

    if (!save.levels || Object.keys(save.levels).length === 0) {
      // Try every previous levels key we've ever used
      for (const oldKey of ['pkm_levels_v2','pkm_levels_v1','pkm_levels']) {
        const old = tryOld(oldKey, null);
        if (old && Object.keys(old).length > 0) { save.levels = old; break; }
      }
    }
    if (!save.coins || save.coins === 0) {
      for (const oldKey of ['pkm_coins_v1','pkm_coins']) {
        const old = tryOld(oldKey, null);
        if (old !== null && !isNaN(parseInt(old,10))) { save.coins = parseInt(old,10)||0; break; }
      }
    }
    if (!save.inventory || Object.keys(save.inventory).length === 0) {
      for (const oldKey of ['pkm_inventory_v1','pkm_inventory']) {
        const old = tryOld(oldKey, null);
        if (old && Object.keys(old).length > 0) { save.inventory = old; break; }
      }
    }
    if (!save.presets || save.presets.every(p=>p===null)) {
      const old = tryOld('pkm_presets', null);
      if (old && Array.isArray(old)) save.presets = old;
    }
    return save;
  }

  /* ── Core load / save ──────────────────────────────────── */
  let _save = null; // cached in memory

  function _loadSave() {
    if (_save) return _save;
    try {
      const raw = localStorage.getItem(SAVE_KEY);
      _save = raw ? JSON.parse(raw) : _defaultSave();
    } catch(e) { _save = _defaultSave(); }
    // Ensure all required fields exist (forward-compat with new fields)
    if (!_save.levels)    _save.levels    = {};
    if (!_save.coins)     _save.coins     = 0;
    if (!_save.inventory) _save.inventory = {};
    if (!_save.presets)   _save.presets   = [null,null,null,null,null];
    if (!_save.shinies)   _save.shinies   = [];
    // Migrate from any old keys
    _save = _migrate(_save);
    _persistSave();
    return _save;
  }

  function _persistSave() {
    try { localStorage.setItem(SAVE_KEY, JSON.stringify(_save)); } catch(e) {}
  }

  /* ── Coins ─────────────────────────────────────────────── */
  function _getCoins() { return _loadSave().coins || 0; }
  function _setCoins(n) {
    _loadSave().coins = Math.max(0, Math.floor(n));
    _persistSave();
    _refreshCoinDisplays();
  }
  function _addCoins(n) { _setCoins(_getCoins() + n); }

  function _refreshCoinDisplays() {
    const c = _getCoins();
    ['pkm-coin-display-lobby','pkm-shop-coins','pkm-lobby-shop-coins'].forEach(id=>{
      const el=document.getElementById(id); if(el) el.textContent=c.toLocaleString();
    });
  }

  /* ── Inventory ─────────────────────────────────────────── */
  function _getInventory() { return _loadSave().inventory || {}; }
  function _setInventory(inv) { _loadSave().inventory = inv; _persistSave(); }
  function _getItemQty(id) { return _getInventory()[id] || 0; }
  function _addItem(id, qty=1) {
    const inv = _getInventory();
    inv[id] = (inv[id]||0) + qty;
    _setInventory(inv);
  }
  function _removeItem(id, qty=1) {
    const inv = _getInventory();
    inv[id] = Math.max(0, (inv[id]||0) - qty);
    if (!inv[id]) delete inv[id];
    _setInventory(inv);
  }
  function _hasItems() { return Object.values(_getInventory()).some(q=>q>0); }

  /* ── Shiny status (persisted per chain base ID) ────────── */
  function _getShinies() { return _loadSave().shinies || []; }
  function _isShiny(baseId) { return _getShinies().includes(String(baseId)); }
  function _setShiny(baseId, on) {
    const s = _getShinies().filter(x=>x!==String(baseId));
    if (on) s.push(String(baseId));
    _loadSave().shinies = s;
    _persistSave();
  }

  /* ── Pokemon progress (levels) ─────────────────────────── */
  function _loadProgress() {
    // No-op — always loaded via _loadSave()
    _loadSave();
    _progressLoaded = true;
  }
  function _saveProgress() { _persistSave(); }

  function _getMonProgress(id) {
    const key = _getChainBaseId(id);
    const levels = _loadSave().levels;
    if (!levels[key]) levels[key] = { level:1, xp:0 };
    return levels[key];
  }
  function _setMonProgress(id, level, xp) {
    const key = _getChainBaseId(id);
    _loadSave().levels[key] = { level, xp };
    _persistSave();
  }

  /* ── Presets ───────────────────────────────────────────── */
  function _loadPresets() {
    const save = _loadSave();
    _presets = save.presets || [null,null,null,null,null];
    while (_presets.length < 5) _presets.push(null);
  }
  function _savePresets() {
    _loadSave().presets = _presets;
    _persistSave();
  }

